--
-- Table structure for table `nms`
--

DROP TABLE IF EXISTS `nms`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `nms` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `sl_no` int(11) NOT NULL,
  `module` varchar(50) NOT NULL,
  `description` text NOT NULL,
  `action_taken` text NOT NULL,
  `observation` text DEFAULT NULL,
  `remarks` text DEFAULT NULL,
  `image_path` text DEFAULT NULL,
  `riu_info_id` int(11) NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_module_record` (`sl_no`,`module`,`riu_info_id`),
  KEY `riu_info_id` (`riu_info_id`),
  KEY `module` (`module`),
  KEY `sl_no` (`sl_no`),
  CONSTRAINT `nms_ibfk_1` FOREIGN KEY (`riu_info_id`) REFERENCES `riu_info` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=155 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

