INSERT INTO `nms` VALUES (42,1,'nms','Ensure E1 network is always healthy and RIU communication is stable.','Verify communication with STCAS unit.','45','45',NULL,70,'2025-11-12 07:07:02','2025-11-12 11:37:02'),(43,2,'nms','Backup the Events &amp; Fault data logs of RIU','Store the log files &amp; Downloaded data from Google drive','','',NULL,70,'2025-11-12 07:07:03','2025-11-12 11:37:03'),(44,3,'nms','Ensure RIU inputs are operated','Check all the RIU field inputs (Signals, Points, Track circuits, etc.,) are operated properly in NMS.','','',NULL,70,'2025-11-12 07:07:03','2025-11-12 11:37:03'),(45,1,'power','Check the Voltage level at 230 v AC Mains input voltage to both the Battery chargers','220 - 260V AC','4512','',NULL,70,'2025-11-12 07:07:09','2025-11-12 11:37:09'),(46,2,'power','Check the working of the A/C input supply monitoring relay for both the channels of A/C 230 V supply input to RIU','Ensure that the A/C supply monitoring relays are in ON condition when A/C power in available.','','',NULL,70,'2025-11-12 07:07:10','2025-11-12 11:37:10'),(47,3,'power','Check the Power voltages at Equipment End of Ch-A &amp; Ch-B','The voltage shall be in the range of 22V to 26.5V','','',NULL,70,'2025-11-12 07:07:10','2025-11-12 11:37:10'),(48,4,'power','Check the mounting arrangementof Input fuse(If Any)','Ensure fuses are fastened securely','','',NULL,70,'2025-11-12 07:07:10','2025-11-12 11:37:10'),(49,5,'power','Check the output Power Supplyvoltage for both Battery charger bank','21.6 ~ 28.8V DC to be observed for final O/P Voltage for both battery banks.','','',NULL,70,'2025-11-12 07:07:10','2025-11-12 11:37:10'),(50,6,'power','Check the connections of the diodes in the charging path from both the battery charger output to batteries.','Ensure that the diodesare firmly connected to TB1 and TB2 in channel 1 and TB3 and TB4 in channel 2 respectively.','','',NULL,70,'2025-11-12 07:07:10','2025-11-12 11:37:10'),(51,7,'power','To check that RIU battery back up is available.','Switch OFF MCBs, ensure that RIU works on battery back up.','','',NULL,70,'2025-11-12 07:07:10','2025-11-12 11:37:10'),(52,8,'power','Clean the Battery Charger and Batteries','To be free from dust','','',NULL,70,'2025-11-12 07:07:10','2025-11-12 11:37:10'),(53,9,'power','Check the voltages at Equipment end of INTERNAL (RIU) Supply','21.6V to 28.8V DCto be observed','','',NULL,70,'2025-11-12 07:07:10','2025-11-12 11:37:10'),(54,10,'power','Check the voltages at Equipment end of EXTERNAL','21.6V to 28.8V DCto be observed','','',NULL,70,'2025-11-12 07:07:10','2025-11-12 11:37:10'),(55,11,'power','Check the all wago fuse indications','Disconnect type fuse wago indications should not glow','','',NULL,70,'2025-11-12 07:07:10','2025-11-12 11:37:10'),(56,1,'earthing','Clean surface of the Earth electrode/MEEB/SEEB','Surface should be kept clean','hi','',NULL,70,'2025-11-12 07:07:23','2025-11-12 11:37:23'),(57,2,'earthing','Measure the Resistance and fillwater in the Earth Pits to keep low soil resistance','Resistance Should be ≤ 2 Ώ','','',NULL,70,'2025-11-12 07:07:23','2025-11-12 11:37:23'),(58,3,'earthing','Check the SPD devices for any signs of physical degradation','Check the Indication LED status of SPD. (If SPD indicates FAIL then replace it)','','',NULL,70,'2025-11-12 07:07:23','2025-11-12 11:37:23'),(60,1,'comm','Check the Quad/OFC','1. Check the firmness of wiring/OFC patch card termination to communication card.\r\n                    2. Ensure OFC routing is properly done with avoiding 90 degree bending','dd','',NULL,70,'2025-11-12 07:07:34','2025-11-12 11:37:34'),(61,2,'comm','Check the Quad/OFC','1. Check the firmness of wiring/OFC patch card termination to communication card.\r\n                  2. Ensure OFC routing is properly done with avoiding 90 degree bending','','',NULL,70,'2025-11-12 07:07:34','2025-11-12 11:37:34'),(62,3,'comm','Check the communication status','Ensure Tx and Rx LED should Glow/Blink','','',NULL,70,'2025-11-12 07:07:34','2025-11-12 11:37:34'),(63,4,'comm','Visually examine all the communication cables areConnected properly and Communication card had tightened','Ensure the tightness of the patch card and communication module.','','',NULL,70,'2025-11-12 07:07:34','2025-11-12 11:37:34'),(65,1,'riu_equip','Visually examine all the cards are inserted properly and tighten the corresponding screws','Ensure the tightness of the cards','fcd','',NULL,70,'2025-11-12 07:07:44','2025-11-12 11:37:44'),(66,2,'riu_equip','Visually examine all PS, communication cables are tighten all the connections / Terminations / Wagoterminals','Ensure the tightness of the cables connectors','','',NULL,70,'2025-11-12 07:07:44','2025-11-12 11:37:44'),(67,3,'riu_equip','Check the RIU Internal and External wirings','1. Check the firmness of wiring Connections from FSC module to Rly. FieldInputs.\r\n                2.Check the firmness ofCommunication cable connections between RIU communication to F M S Unit\r\n                3.Check the firmness of wiring connections between Battery Charger .','','',NULL,70,'2025-11-12 07:07:44','2025-11-12 11:37:44'),(68,4,'riu_equip','Check the output Supply voltage of 24 Volts charger provided for relay input wiring','The voltage measured should be approx. 21V - 29V DC.','','',NULL,70,'2025-11-12 07:07:44','2025-11-12 11:37:44'),(69,5,'riu_equip','Check voltage from contacts of field input relays at terminals. witred to RIU.','The voltage on the terminals when the relay is picked up should be between 20 to 29V DC.','','',NULL,70,'2025-11-12 07:07:44','2025-11-12 11:37:44'),(71,1,'nms','Ensure E1 network is always healthy and RIU communication is stable.','Verify communication with STCAS unit.','po','po',NULL,73,'2025-11-12 07:45:28','2025-11-12 12:15:28'),(72,2,'nms','Backup the Events &amp; Fault data logs of RIU','Store the log files &amp; Downloaded data from Google drive','','',NULL,73,'2025-11-12 07:45:28','2025-11-12 12:15:28'),(73,3,'nms','Ensure RIU inputs are operated','Check all the RIU field inputs (Signals, Points, Track circuits, etc.,) are operated properly in NMS.','','',NULL,73,'2025-11-12 07:45:29','2025-11-12 12:15:29'),(74,1,'power','Check the Voltage level at 230 v AC Mains input voltage to both the Battery chargers','220 - 260V AC','po','po',NULL,73,'2025-11-12 07:46:25','2025-11-12 12:16:25'),(75,2,'power','Check the working of the A/C input supply monitoring relay for both the channels of A/C 230 V supply input to RIU','Ensure that the A/C supply monitoring relays are in ON condition when A/C power in available.','','',NULL,73,'2025-11-12 07:46:25','2025-11-12 12:16:25'),(76,3,'power','Check the Power voltages at Equipment End of Ch-A &amp; Ch-B','The voltage shall be in the range of 22V to 26.5V','','',NULL,73,'2025-11-12 07:46:25','2025-11-12 12:16:25'),(77,4,'power','Check the mounting arrangementof Input fuse(If Any)','Ensure fuses are fastened securely','','',NULL,73,'2025-11-12 07:46:25','2025-11-12 12:16:25'),(78,5,'power','Check the output Power Supplyvoltage for both Battery charger bank','21.6 ~ 28.8V DC to be observed for final O/P Voltage for both battery banks.','','',NULL,73,'2025-11-12 07:46:25','2025-11-12 12:16:25'),(79,6,'power','Check the connections of the diodes in the charging path from both the battery charger output to batteries.','Ensure that the diodesare firmly connected to TB1 and TB2 in channel 1 and TB3 and TB4 in channel 2 respectively.','','',NULL,73,'2025-11-12 07:46:25','2025-11-12 12:16:25'),(80,7,'power','To check that RIU battery back up is available.','Switch OFF MCBs, ensure that RIU works on battery back up.','','',NULL,73,'2025-11-12 07:46:25','2025-11-12 12:16:25'),(81,8,'power','Clean the Battery Charger and Batteries','To be free from dust','','',NULL,73,'2025-11-12 07:46:25','2025-11-12 12:16:25'),(82,9,'power','Check the voltages at Equipment end of INTERNAL (RIU) Supply','21.6V to 28.8V DCto be observed','','',NULL,73,'2025-11-12 07:46:25','2025-11-12 12:16:25'),(83,10,'power','Ch