--
-- Table structure for table `quarterly_check`
--

DROP TABLE IF EXISTS `quarterly_check`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `quarterly_check` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `s_no` int(11) NOT NULL,
  `station_info_id` int(11) NOT NULL,
  `module` varchar(50) DEFAULT NULL,
  `details` varchar(255) DEFAULT NULL,
  `name_number` varchar(255) DEFAULT NULL,
  `date_commission` date DEFAULT NULL,
  `required_value` varchar(255) DEFAULT NULL,
  `observed_value` varchar(255) DEFAULT NULL,
  `remarks` text DEFAULT NULL,
  `image_path` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_row` (`station_info_id`,`s_no`,`module`),
  CONSTRAINT `quarterly_check_ibfk_1` FOREIGN KEY (`station_info_id`) REFERENCES `station_info` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=529 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

