--
-- Table structure for table `quarterly_half`
--

DROP TABLE IF EXISTS `quarterly_half`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `quarterly_half` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `s_no` int(11) NOT NULL,
  `station_info_id` int(11) NOT NULL,
  `module` varchar(50) DEFAULT NULL,
  `maintenance_task_description` varchar(255) DEFAULT NULL,
  `location` varchar(255) DEFAULT NULL,
  `frequency` varchar(100) DEFAULT NULL,
  `action_taken` varchar(255) DEFAULT NULL,
  `equipment_condition` varchar(255) DEFAULT NULL,
  `remarks` text DEFAULT NULL,
  `image_path` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_row` (`station_info_id`,`s_no`,`module`),
  CONSTRAINT `quarterly_half_ibfk_1` FOREIGN KEY (`station_info_id`) REFERENCES `station_info` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=162 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

